/* Simple JSON string value extractor. Returns malloc'd string or NULL. */
static char *json_get_string(const char *json, const char *key) {
    /* Look for "key" */
    char search[256];
    snprintf(search, sizeof(search), "\"%s\"", key);
    const char *pos = strstr(json, search);
    if (!pos) return NULL;
    pos += strlen(search);
    /* Skip whitespace and colon */
    while (*pos && (isspace((unsigned char)*pos) || *pos == ':')) pos++;
    if (*pos == '\0') return NULL;
    if (*pos == 'n' && strncmp(pos, "null", 4) == 0) return NULL;
    if (*pos != '"') return NULL;
    pos++; /* skip opening quote */

    /* Parse the string value handling escapes */
    size_t buf_size = 1024;
    char *buf = malloc(buf_size);
    size_t buf_len = 0;

    while (*pos && *pos != '"') {
        if (buf_len + 8 >= buf_size) {
            buf_size *= 2;
            buf = realloc(buf, buf_size);
        }
        if (*pos == '\\') {
            pos++;
            switch (*pos) {
                case '"': buf[buf_len++] = '"'; break;
                case '\\': buf[buf_len++] = '\\'; break;
                case '/': buf[buf_len++] = '/'; break;
                case 'n': buf[buf_len++] = '\n'; break;
                case 'r': buf[buf_len++] = '\r'; break;
                case 't': buf[buf_len++] = '\t'; break;
                case 'b': buf[buf_len++] = '\b'; break;
                case 'f': buf[buf_len++] = '\f'; break;
                case 'u': {
                    /* Basic \uXXXX handling - just pass through as UTF-8 for ASCII range */
                    if (pos[1] && pos[2] && pos[3] && pos[4]) {
                        unsigned int cp = 0;
                        sscanf(pos + 1, "%4x", &cp);
                        if (cp < 0x80) {
                            buf[buf_len++] = (char)cp;
                        } else if (cp < 0x800) {
                            buf[buf_len++] = (char)(0xC0 | (cp >> 6));
                            buf[buf_len++] = (char)(0x80 | (cp & 0x3F));
                        } else {
                            buf[buf_len++] = (char)(0xE0 | (cp >> 12));
                            buf[buf_len++] = (char)(0x80 | ((cp >> 6) & 0x3F));
                            buf[buf_len++] = (char)(0x80 | (cp & 0x3F));
                        }
                        pos += 4;
                    }
                    break;
                }
                default: buf[buf_len++] = *pos; break;
            }
        } else {
            buf[buf_len++] = *pos;
        }
        pos++;
    }
    buf[buf_len] = '\0';
    return buf;
}

/* Check if a key exists in JSON (even if value is empty string) */
static int json_has_key(const char *json, const char *key) {
    char search[256];
    snprintf(search, sizeof(search), "\"%s\"", key);
    return strstr(json, search) != NULL;
}

/* Extract note ID from URL like /api/notes/123 */
static int extract_note_id(const char *url) {
    const char *prefix = "/api/notes/";
    if (strncmp(url, prefix, strlen(prefix)) != 0) return -1;
    const char *id_str = url + strlen(prefix);
    if (*id_str == '\0') return -1;
    /* Check it's all digits */
    for (const char *p = id_str; *p; p++) {
        if (!isdigit((unsigned char)*p)) return -1;
    }
    return atoi(id_str);
}

static enum MHD_Result handle_get_notes(struct MHD_Connection *connection) {
    /* Parse limit and offset from query params */
    int limit = 50;
    int offset = 0;

    const char *limit_str = MHD_lookup_connection_value(connection, MHD_GET_ARGUMENT_KIND, "limit");
    const char *offset_str = MHD_lookup_connection_value(connection, MHD_GET_ARGUMENT_KIND, "offset");

    if (limit_str) {
        limit = atoi(limit_str);
        if (limit <= 0) limit = 50;
        if (limit > 100) limit = 100;
    }
    if (offset_str) {
        offset = atoi(offset_str);
        if (offset < 0) offset = 0;
    }

    int total = get_total_notes_count();
    char *json = get_notes_paginated_json(limit, offset);
    if (!json) json = strdup("[]");

    char total_str[32];
    snprintf(total_str, sizeof(total_str), "%d", total);

    enum MHD_Result r = send_response(connection, json, MHD_HTTP_OK, total_str);
    free(json);
    return r;
}

static enum MHD_Result handle_get_note(struct MHD_Connection *connection, int id) {
