static enum MHD_Result handle_post_note(struct MHD_Connection *connection, const char *body) {
    if (!body || strlen(body) == 0) {
        return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
    }

    char *title = json_get_string(body, "title");

    /* Title must be present and non-empty */
    if (!title || strlen(title) == 0) {
        if (title) free(title);
        return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
    }

    /* Check if title is only whitespace */
    int all_space = 1;
    for (size_t i = 0; i < strlen(title); i++) {
        if (!isspace((unsigned char)title[i])) { all_space = 0; break; }
    }
    if (all_space) {
        free(title);
        return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
    }

    char *content = json_get_string(body, "content");
    if (!content) content = strdup("");

    int id = create_note(title, content);
    if (id < 0) {
        free(title);
        free(content);
        return send_json(connection, "{\"error\":\"internal error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
    }

    /* Return the created note */
    char *note_json = get_note_json(id);
    if (!note_json) {
        free(title);
        free(content);
        return send_json(connection, "{\"error\":\"internal error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
    }

    enum MHD_Result r = send_json(connection, note_json, MHD_HTTP_CREATED);
    free(note_json);
    free(title);
    free(content);
    return r;
}

static enum MHD_Result handle_put_note(struct MHD_Connection *connection, int id, const char *body) {
    if (!body || strlen(body) == 0) {
        return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
    }

    char *title = json_get_string(body, "title");

    /* Title must be present and non-empty */
    if (!title || strlen(title) == 0) {
        if (title) free(title);
        return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
    }

    /* Check if title is only whitespace */
    int all_space = 1;
    for (size_t i = 0; i < strlen(title); i++) {
        if (!isspace((unsigned char)title[i])) { all_space = 0; break; }
    }
    if (all_space) {
        free(title);
        return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
    }

    char *content = json_get_string(body, "content");
    if (!content) content = strdup("");

    int result = update_note(id, title, content);
    free(title);
    free(content);

    if (result == 0) {
        return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
    }
    if (result < 0) {
        return send_json(connection, "{\"error\":\"internal error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
    }

    char *note_json = get_note_json(id);
    if (!note_json) {
        return send_json(connection, "{\"error\":\"internal error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
    }
    enum MHD_Result r = send_json(connection, note_json, MHD_HTTP_OK);
    free(note_json);
    return r;
}

static enum MHD_Result handle_delete_note(struct MHD_Connection *connection, int id) {
    int result = delete_note(id);
    if (result == 0) {
        return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
    }
    return send_json(connection, "{\"status\":\"deleted\"}", MHD_HTTP_OK);
}

enum MHD_Result route_request(struct MHD_Connection *connection, const char *url,
                              const char *method, const char *upload_data,
                              size_t *upload_data_size, void **con_cls) {

    /* OPTIONS preflight */
    if (strcmp(method, "OPTIONS") == 0) {
        return send_options(connection);
    }

    /* For POST/PUT/DELETE, we need to accumulate body data */
    if (strcmp(method, "POST") == 0 || strcmp(method, "PUT") == 0 || strcmp(method, "DELETE") == 0) {
        if (*con_cls == NULL) {
            /* First call - allocate connection info */
            struct connection_info *ci = calloc(1, sizeof(struct connection_info));
            ci->data = NULL;
            ci->data_size = 0;
            *con_cls = ci;
            return MHD_YES;
        }

        struct connection_info *ci = *con_cls;

        if (*upload_data_size > 0) {
            /* Check body size limit */
            if (ci->data_size + *upload_data_size > MAX_BODY_SIZE) {
                *upload_data_size = 0;
                return send_json(connection, "{\"error\":\"body too large\"}", 413);
            }
            /* Accumulate data */
            ci->data = realloc(ci->data, ci->data_size + *upload_data_size + 1);
            memcpy(ci->data + ci->data_size, upload_data, *upload_data_size);
            ci->data_size += *upload_data_size;
            ci->data[ci->data_size] = '\0';
            *upload_data_size = 0;
            return MHD_YES;
        }

        /* All data received - process the request */
        /* Check auth for mutating requests */
        if (!api_key_valid(connection)) {
            return send_json(connection, "{\"error\":\"unauthorized\"}", MHD_HTTP_UNAUTHORIZED);
        }

        /* Check body size */
        if (ci->data_size > MAX_BODY_SIZE) {
            return send_json(connection, "{\"error\":\"body too large\"}", 413);
        }

        /* Route to appropriate handler */
        if (strcmp(url, "/api/notes") == 0 && strcmp(method, "POST") == 0) {
            return handle_post_note(connection, ci->data);
        }

        /* Extract ID for /api/notes/{id} routes */
        int id = extract_note_id(url);
        if (id < 0) {
            return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
        }

        if (strcmp(method, "PUT") == 0) {
            return handle_put_note(connection, id, ci->data);
        }
        if (strcmp(method, "DELETE") == 0) {
            return handle_delete_note(connection, id);
        }

        return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
    }

    /* GET requests */
    if (strcmp(method, "GET") == 0) {
        if (strcmp(url, "/api/notes") == 0) {
            return handle_get_notes(connection);
        }

        int id = extract_note_id(url);
        if (id >= 0) {
            return handle_get_note(connection, id);
        }

        return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
    }

    return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
}
