#include "routes.h"
#include "db.h"
#include "auth.h"
#include <microhttpd.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>

static enum MHD_Result send_response(struct MHD_Connection *connection,
    const char *body, unsigned int status, const char *total_count) {
    struct MHD_Response *response = MHD_create_response_from_buffer(
        strlen(body), (void *)body, MHD_RESPMEM_MUST_COPY);
    MHD_add_response_header(response, "Content-Type", "application/json");
    MHD_add_response_header(response, "Access-Control-Allow-Origin", "*");
    MHD_add_response_header(response, "Access-Control-Allow-Methods", "GET, POST, PUT, DELETE, OPTIONS");
    MHD_add_response_header(response, "Access-Control-Allow-Headers", "Content-Type, X-API-Key");
    if (total_count) {
        MHD_add_response_header(response, "X-Total-Count", total_count);
    }
    enum MHD_Result ret = MHD_queue_response(connection, status, response);
    MHD_destroy_response(response);
    return ret;
}

static enum MHD_Result send_json(struct MHD_Connection *connection,
    const char *body, unsigned int status) {
    return send_response(connection, body, status, NULL);
}

static enum MHD_Result send_options(struct MHD_Connection *connection) {
    struct MHD_Response *response = MHD_create_response_from_buffer(0, (void*)"", MHD_RESPMEM_PERSISTENT);
    MHD_add_response_header(response, "Access-Control-Allow-Origin", "*");
    MHD_add_response_header(response, "Access-Control-Allow-Methods", "GET, POST, PUT, DELETE, OPTIONS");
    MHD_add_response_header(response, "Access-Control-Allow-Headers", "Content-Type, X-API-Key");
    MHD_add_response_header(response, "Content-Type", "application/json");
    enum MHD_Result ret = MHD_queue_response(connection, MHD_HTTP_OK, response);
    MHD_destroy_response(response);
    return ret;
}

/* Simple JSON string value extractor. Returns malloc'd string or NULL. */
static char *json_get_string(const char *json, const char *key) {
    char search[256];
    snprintf(search, sizeof(search), "\"%s\"", key);
    const char *pos = strstr(json, search);
    if (!pos) return NULL;
    pos += strlen(search);
    while (*pos && (isspace((unsigned char)*pos) || *pos == ':')) pos++;
    if (*pos == '\0') return NULL;
    if (*pos == 'n' && strncmp(pos, "null", 4) == 0) return NULL;
    if (*pos != '"') return NULL;
    pos++;

    size_t buf_size = 1024;
    char *buf = malloc(buf_size);
    size_t buf_len = 0;

    while (*pos && *pos != '"') {
        if (buf_len + 8 >= buf_size) {
            buf_size *= 2;
            buf = realloc(buf, buf_size);
        }
        if (*pos == '\\') {
            pos++;
            switch (*pos) {
                case '"': buf[buf_len++] = '"'; break;
                case '\\': buf[buf_len++] = '\\'; break;
                case '/': buf[buf_len++] = '/'; break;
                case 'n': buf[buf_len++] = '\n'; break;
                case 'r': buf[buf_len++] = '\r'; break;
                case 't': buf[buf_len++] = '\t'; break;
                case 'b': buf[buf_len++] = '\b'; break;
                case 'f': buf[buf_len++] = '\f'; break;
                case 'u': {
                    if (pos[1] && pos[2] && pos[3] && pos[4]) {
                        unsigned int cp = 0;
                        sscanf(pos + 1, "%4x", &cp);
                        if (cp < 0x80) {
                            buf[buf_len++] = (char)cp;
                        } else if (cp < 0x800) {
                            buf[buf_len++] = (char)(0xC0 | (cp >> 6));
                            buf[buf_len++] = (char)(0x80 | (cp & 0x3F));
                        } else {
                            buf[buf_len++] = (char)(0xE0 | (cp >> 12));
                            buf[buf_len++] = (char)(0x80 | ((cp >> 6) & 0x3F));
                            buf[buf_len++] = (char)(0x80 | (cp & 0x3F));
                        }
                        pos += 4;
                    }
                    break;
                }
                default: buf[buf_len++] = *pos; break;
            }
        } else {
            buf[buf_len++] = *pos;
        }
        pos++;
    }
    buf[buf_len] = '\0';
    return buf;
}

/* Extract note ID from URL like /api/notes/123 */
static int extract_note_id(const char *url) {
    const char *prefix = "/api/notes/";
    if (strncmp(url, prefix, strlen(prefix)) != 0) return -1;
    const char *id_str = url + strlen(prefix);
    if (*id_str == '\0') return -1;
    for (const char *p = id_str; *p; p++) {
        if (!isdigit((unsigned char)*p)) return -1;
    }
    return atoi(id_str);
}

static enum MHD_Result handle_get_notes(struct MHD_Connection *connection) {
    int limit = 50;
    int offset = 0;

    const char *limit_str = MHD_lookup_connection_value(connection, MHD_GET_ARGUMENT_KIND, "limit");
    const char *offset_str = MHD_lookup_connection_value(connection, MHD_GET_ARGUMENT_KIND, "offset");

    if (limit_str) {
        limit = atoi(limit_str);
        if (limit <= 0) limit = 50;
        if (limit > 100) limit = 100;
    }
    if (offset_str) {
        offset = atoi(offset_str);
        if (offset < 0) offset = 0;
    }

    int total = get_total_notes_count();
    char *json = get_notes_paginated_json(limit, offset);
    if (!json) json = strdup("[]");

    char total_str[32];
    snprintf(total_str, sizeof(total_str), "%d", total);

    enum MHD_Result r = send_response(connection, json, MHD_HTTP_OK, total_str);
    free(json);
    return r;
}

static enum MHD_Result handle_get_note(struct MHD_Connection *connection, int id) {
    char *json = get_note_json(id);
    if (!json) {
        return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
    }
    enum MHD_Result r = send_json(connection, json, MHD_HTTP_OK);
    free(json);
    return r;
}

static enum MHD_Result handle_post_note(struct MHD_Connection *connection, const char *body) {
    if (!body || strlen(body) == 0) {
        return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
    }

    char *title = json_get_string(body, "title");

    if (!title || strlen(title) == 0) {
        if (title) free(title);
        return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
    }

    int all_space = 1;
    for (size_t i = 0; i < strlen(title); i++) {
        if (!isspace((unsigned char)title[i])) { all_space = 0; break; }
    }
    if (all_space) {
        free(title);
        return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
    }

    char *content = json_get_string(body, "content");
    if (!content) content = strdup("");

    int id = create_note(title, content);
    if (id < 0) {
        free(title);
        free(content);
        return send_json(connection, "{\"error\":\"internal error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
    }

    char *note_json = get_note_json(id);
    if (!note_json) {
        free(title);
        free(content);
        return send_json(connection, "{\"error\":\"internal error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
    }

    enum MHD_Result r = send_json(connection, note_json, MHD_HTTP_CREATED);
    free(note_json);
    free(title);
    free(content);
    return r;
}

static enum MHD_Result handle_put_note(struct MHD_Connection *connection, int id, const char *body) {
    if (!body || strlen(body) == 0) {
        return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
    }

    char *title = json_get_string(body, "title");

    if (!title || strlen(title) == 0) {
        if (title) free(title);
        return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
    }

    int all_space = 1;
    for (size_t i = 0; i < strlen(title); i++) {
        if (!isspace((unsigned char)title[i])) { all_space = 0; break; }
    }
    if (all_space) {
        free(title);
        return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
    }

    char *content = json_get_string(body, "content");
    if (!content) content = strdup("");

    int result = update_note(id, title, content);
    free(title);
    free(content);

    if (result == 0) {
        return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
    }
    if (result < 0) {
        return send_json(connection, "{\"error\":\"internal error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
    }

    char *note_json = get_note_json(id);
    if (!note_json) {
        return send_json(connection, "{\"error\":\"internal error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
    }
    enum MHD_Result r = send_json(connection, note_json, MHD_HTTP_OK);
    free(note_json);
    return r;
}

static enum MHD_Result handle_delete_note(struct MHD_Connection *connection, int id) {
    int result = delete_note(id);
    if (result == 0) {
        return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
    }
    return send_json(connection, "{\"status\":\"deleted\"}", MHD_HTTP_OK);
}

enum MHD_Result route_request(struct MHD_Connection *connection, const char *url,
                              const char *method, const char *upload_data,
                              size_t *upload_data_size, void **con_cls) {

    /* OPTIONS preflight */
    if (strcmp(method, "OPTIONS") == 0) {
        return send_options(connection);
    }

    /* For POST/PUT/DELETE, we need to accumulate body data */
    if (strcmp(method, "POST") == 0 || strcmp(method, "PUT") == 0 || strcmp(method, "DELETE") == 0) {
        if (*con_cls == NULL) {
            struct connection_info *ci = calloc(1, sizeof(struct connection_info));
            ci->data = NULL;
            ci->data_size = 0;
            ci->too_large = 0;
            *con_cls = ci;
            return MHD_YES;
        }

        struct connection_info *ci = *con_cls;

        if (*upload_data_size > 0) {
            if (ci->too_large || ci->data_size + *upload_data_size > MAX_BODY_SIZE) {
                ci->too_large = 1;
