static sqlite3 *db = NULL;
static pthread_mutex_t db_mutex = PTHREAD_MUTEX_INITIALIZER;

/* Escape a string for JSON output. Caller must free result. */
static char *json_escape(const char *s) {
    if (!s) return strdup("");
    size_t len = strlen(s);
    /* Worst case: every char becomes \uXXXX (6 chars) */
    char *out = malloc(len * 6 + 1);
    if (!out) return strdup("");
    char *p = out;
    for (size_t i = 0; i < len; i++) {
        unsigned char c = (unsigned char)s[i];
        switch (c) {
            case '"':  *p++ = '\\'; *p++ = '"'; break;
            case '\\': *p++ = '\\'; *p++ = '\\'; break;
            case '\n': *p++ = '\\'; *p++ = 'n'; break;
            case '\r': *p++ = '\\'; *p++ = 'r'; break;
            case '\t': *p++ = '\\'; *p++ = 't'; break;
            case '\b': *p++ = '\\'; *p++ = 'b'; break;
            case '\f': *p++ = '\\'; *p++ = 'f'; break;
            default:
                if (c < 0x20) {
                    p += sprintf(p, "\\u%04x", c);
                } else {
                    *p++ = c;
                }
                break;
        }
    }
    *p = '\0';
    return out;
}

int init_db(const char *path) {
    int rc = sqlite3_open_v2(path, &db,
        SQLITE_OPEN_READWRITE | SQLITE_OPEN_CREATE | SQLITE_OPEN_FULLMUTEX,
        NULL);
    if (rc != SQLITE_OK) {
        fprintf(stderr, "Cannot open database: %s\n", sqlite3_errmsg(db));
        return -1;
    }

    /* Enable WAL mode for concurrency */
    sqlite3_exec(db, "PRAGMA journal_mode=WAL;", NULL, NULL, NULL);
    /* Set busy timeout to 5 seconds */
    sqlite3_busy_timeout(db, 5000);

    const char *sql = "CREATE TABLE IF NOT EXISTS notes ("
                      "id INTEGER PRIMARY KEY AUTOINCREMENT,"
                      "title TEXT NOT NULL,"
                      "content TEXT NOT NULL DEFAULT ''"
                      ");";
    char *err_msg = NULL;
    if (sqlite3_exec(db, sql, NULL, NULL, &err_msg) != SQLITE_OK) {
        fprintf(stderr, "SQL error: %s\n", err_msg);
        sqlite3_free(err_msg);
        return -1;
    }
    return 0;
}

void close_db(void) {
    if (db) sqlite3_close(db);
    db = NULL;
}

int create_note(const char *title, const char *content) {
    if (!content) content = "";
    pthread_mutex_lock(&db_mutex);
    sqlite3_stmt *stmt;
    const char *sql = "INSERT INTO notes (title, content) VALUES (?, ?);";
    int rc = sqlite3_prepare_v2(db, sql, -1, &stmt, NULL);
    if (rc != SQLITE_OK) {
        pthread_mutex_unlock(&db_mutex);
        return -1;
    }
    sqlite3_bind_text(stmt, 1, title, -1, SQLITE_TRANSIENT);
    sqlite3_bind_text(stmt, 2, content, -1, SQLITE_TRANSIENT);
    rc = sqlite3_step(stmt);
    sqlite3_finalize(stmt);
    if (rc != SQLITE_DONE) {
        pthread_mutex_unlock(&db_mutex);
        return -1;
    }
    int id = (int)sqlite3_last_insert_rowid(db);
    pthread_mutex_unlock(&db_mutex);
    return id;
}

char *get_note_json(int id) {
    pthread_mutex_lock(&db_mutex);
    sqlite3_stmt *stmt;
    const char *sql = "SELECT id, title, content FROM notes WHERE id = ?;";
    int rc = sqlite3_prepare_v2(db, sql, -1, &stmt, NULL);
    if (rc != SQLITE_OK) {
        pthread_mutex_unlock(&db_mutex);
        return NULL;
    }
    sqlite3_bind_int(stmt, 1, id);
    rc = sqlite3_step(stmt);
    if (rc != SQLITE_ROW) {
        sqlite3_finalize(stmt);
        pthread_mutex_unlock(&db_mutex);
        return NULL;
    }
    int nid = sqlite3_column_int(stmt, 0);
    const char *title = (const char *)sqlite3_column_text(stmt, 1);
    const char *content = (const char *)sqlite3_column_text(stmt, 2);
    char *esc_title = json_escape(title);
    char *esc_content = json_escape(content);
    size_t buf_size = strlen(esc_title) + strlen(esc_content) + 100;
    char *json = malloc(buf_size);
    snprintf(json, buf_size, "{\"id\":%d,\"title\":\"%s\",\"content\":\"%s\"}",
             nid, esc_title, esc_content);
    free(esc_title);
    free(esc_content);
    sqlite3_finalize(stmt);
    pthread_mutex_unlock(&db_mutex);
    return json;
}

char *get_notes_paginated_json(int limit, int offset) {
    pthread_mutex_lock(&db_mutex);
    sqlite3_stmt *stmt;
    const char *sql = "SELECT id, title, content FROM notes ORDER BY id LIMIT ? OFFSET ?;";
    int rc = sqlite3_prepare_v2(db, sql, -1, &stmt, NULL);
    if (rc != SQLITE_OK) {
        pthread_mutex_unlock(&db_mutex);
        return strdup("[]");
    }
    sqlite3_bind_int(stmt, 1, limit);
    sqlite3_bind_int(stmt, 2, offset);

    /* Build JSON array */
    size_t buf_size = 4096;
    size_t buf_used = 0;
    char *buf = malloc(buf_size);
    buf[0] = '[';
    buf_used = 1;
    int first = 1;

    while ((rc = sqlite3_step(stmt)) == SQLITE_ROW) {
        int nid = sqlite3_column_int(stmt, 0);
        const char *title = (const char *)sqlite3_column_text(stmt, 1);
        const char *content = (const char *)sqlite3_column_text(stmt, 2);
        char *esc_title = json_escape(title);
        char *esc_content = json_escape(content);

        size_t entry_size = strlen(esc_title) + strlen(esc_content) + 100;
        while (buf_used + entry_size + 10 > buf_size) {
            buf_size *= 2;
            buf = realloc(buf, buf_size);
        }
        if (!first) { buf[buf_used++] = ','; }
        first = 0;
        buf_used += snprintf(buf + buf_used, buf_size - buf_used,
            "{\"id\":%d,\"title\":\"%s\",\"content\":\"%s\"}",
            nid, esc_title, esc_content);
        free(esc_title);
        free(esc_content);
    }
    sqlite3_finalize(stmt);
    pthread_mutex_unlock(&db_mutex);

    if (buf_used + 2 > buf_size) {
        buf_size = buf_used + 2;
        buf = realloc(buf, buf_size);
    }
    buf[buf_used++] = ']';
    buf[buf_used] = '\0';
    return buf;
}

int get_total_notes_count(void) {
    pthread_mutex_lock(&db_mutex);
    sqlite3_stmt *stmt;
    const char *sql = "SELECT COUNT(*) FROM notes;";
    int rc = sqlite3_prepare_v2(db, sql, -1, &stmt, NULL);
    if (rc != SQLITE_OK) {
        pthread_mutex_unlock(&db_mutex);
        return 0;
    }
    rc = sqlite3_step(stmt);
    int count = 0;
    if (rc == SQLITE_ROW) {
        count = sqlite3_column_int(stmt, 0);
    }
    sqlite3_finalize(stmt);
    pthread_mutex_unlock(&db_mutex);
    return count;
}

int note_exists(int id) {
    pthread_mutex_lock(&db_mutex);
    sqlite3_stmt *stmt;
    const char *sql = "SELECT 1 FROM notes WHERE id = ?;";
    int rc = sqlite3_prepare_v2(db, sql, -1, &stmt, NULL);
    if (rc != SQLITE_OK) {
        pthread_mutex_unlock(&db_mutex);
        return 0;
    }
    sqlite3_bind_int(stmt, 1, id);
    rc = sqlite3_step(stmt);
    int exists = (rc == SQLITE_ROW) ? 1 : 0;
    sqlite3_finalize(stmt);
    pthread_mutex_unlock(&db_mutex);
    return exists;
}

int update_note(int id, const char *title, const char *content) {
    if (!content) content = "";
    pthread_mutex_lock(&db_mutex);
    /* Check existence first */
    sqlite3_stmt *stmt;
    const char *check_sql = "SELECT 1 FROM notes WHERE id = ?;";
    int rc = sqlite3_prepare_v2(db, check_sql, -1, &stmt, NULL);
    if (rc != SQLITE_OK) {
        pthread_mutex_unlock(&db_mutex);
        return -1;
    }
    sqlite3_bind_int(stmt, 1, id);
    rc = sqlite3_step(stmt);
    sqlite3_finalize(stmt);
    if (rc != SQLITE_ROW) {
        pthread_mutex_unlock(&db_mutex);
        return 0; /* not found */
    }

    const char *sql = "UPDATE notes SET title = ?, content = ? WHERE id = ?;";
    rc = sqlite3_prepare_v2(db, sql, -1, &stmt, NULL);
    if (rc != SQLITE_OK) {
        pthread_mutex_unlock(&db_mutex);
        return -1;
    }
    sqlite3_bind_text(stmt, 1, title, -1, SQLITE_TRANSIENT);
    sqlite3_bind_text(stmt, 2, content, -1, SQLITE_TRANSIENT);
    sqlite3_bind_int(stmt, 3, id);
    rc = sqlite3_step(stmt);
    sqlite3_finalize(stmt);
    pthread_mutex_unlock(&db_mutex);
    return (rc == SQLITE_DONE) ? 1 : -1;
}

int delete_note(int id) {
    pthread_mutex_lock(&db_mutex);
    /* Check existence first */
    sqlite3_stmt *stmt;
    const char *check_sql = "SELECT 1 FROM notes WHERE id = ?;";
    int rc = sqlite3_prepare_v2(db, check_sql, -1, &stmt, NULL);
    if (rc != SQLITE_OK) {
        pthread_mutex_unlock(&db_mutex);
        return 0;
    }
    sqlite3_bind_int(stmt, 1, id);
    rc = sqlite3_step(stmt);
    sqlite3_finalize(stmt);
    if (rc != SQLITE_ROW) {
        pthread_mutex_unlock(&db_mutex);
        return 0; /* not found */
    }

    const char *sql = "DELETE FROM notes WHERE id = ?;";
    rc = sqlite3_prepare_v2(db, sql, -1, &stmt, NULL);
    if (rc != SQLITE_OK) {
        pthread_mutex_unlock(&db_mutex);
        return 0;
    }
    sqlite3_bind_int(stmt, 1, id);
    rc = sqlite3_step(stmt);
    sqlite3_finalize(stmt);
    pthread_mutex_unlock(&db_mutex);
    return (rc == SQLITE_DONE) ? 1 : 0;
}
