/* Decode a single %XX hex sequence; returns the char or -1 on failure */
static int decode_hex(const char *s) {
    if (s[0] != '%') return -1;
    char hi = s[1], lo = s[2];
    if (!isxdigit((unsigned char)hi) || !isxdigit((unsigned char)lo)) return -1;
    unsigned int val = 0;
    sscanf(s+1, "%2x", &val);
